import{_ as i,o as e,c as a,ae as t}from"./chunks/framework.BdQd5MxT.js";const u=JSON.parse('{"title":"Google DeepMind 工程实践深度分析：Agent Skills 如何补知识差距，但也暴露更新与主权问题","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/google-deepmind-agent-skills-knowledge-gap.md","filePath":"bestpractice/google-deepmind-agent-skills-knowledge-gap.md"}'),o={name:"bestpractice/google-deepmind-agent-skills-knowledge-gap.md"};function r(n,l,s,p,d,g){return e(),a("div",null,[...l[0]||(l[0]=[t('<h1 id="google-deepmind-工程实践深度分析-agent-skills-如何补知识差距-但也暴露更新与主权问题" tabindex="-1">Google DeepMind 工程实践深度分析：Agent Skills 如何补知识差距，但也暴露更新与主权问题 <a class="header-anchor" href="#google-deepmind-工程实践深度分析-agent-skills-如何补知识差距-但也暴露更新与主权问题" aria-label="Permalink to &quot;Google DeepMind 工程实践深度分析：Agent Skills 如何补知识差距，但也暴露更新与主权问题&quot;">​</a></h1><blockquote><p>来源：</p><ol><li><a href="https://developers.googleblog.com/closing-the-knowledge-gap-with-agent-skills/" target="_blank" rel="noreferrer">Closing the knowledge gap with agent skills</a> (Google Developers Blog, 2026-03-25)</li><li><a href="https://github.com/google-gemini/gemini-skills/" target="_blank" rel="noreferrer">Gemini Skills GitHub</a></li><li>文中引用的 Vercel Agents.md eval 结果与 Gemini CLI skill activation 机制</li></ol><p>分析师：WLB + GSD（文件协作模式） 分析日期：2026-04-15</p></blockquote><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>Google DeepMind 这篇文章最值得看的，不是“我们也做了一个 skill”，而是它把一个长期存在但经常被低估的问题直接摊开了：<strong>模型能力在变强，但工程知识是会过期的。</strong> 他们用 Gemini API developer skill 证明，轻量知识注入确实能把 SDK 使用正确率从很低的 baseline 拉到可用水平，但也同时承认了两个更关键的现实：<strong>AGENTS.md 往往比 skill 更有效，skill 更新机制如果不解决，迟早会反噬。</strong></p><hr><h2 id="_1-这篇真正回答了什么问题" tabindex="-1">1. 这篇真正回答了什么问题 <a class="header-anchor" href="#_1-这篇真正回答了什么问题" aria-label="Permalink to &quot;1. 这篇真正回答了什么问题&quot;">​</a></h2><p>过去我们讨论 coding agent，常常把失败归因于模型推理不够强、上下文不够长、工具不够全。</p><p>但 Google 这篇文章指出了另一个更基础的问题：</p><ul><li>模型训练完成后，知识就冻结了</li><li>SDK、模型版本、最佳实践却还在持续变化</li><li>即使模型会写代码，也可能默认写出已经过时的调用方式</li></ul><p>文章里举的例子非常典型：</p><ul><li>模型不知道训练后自己生态发生了什么变化</li><li>模型不知道新的 SDK 推荐路径</li><li>模型不知道 subtle engineering best practice 更新，比如 thought circulation</li></ul><p>这不是一个“答得不够聪明”的问题，而是一个<strong>知识供应链滞后</strong>的问题。</p><hr><h2 id="_2-google-到底做了什么" tabindex="-1">2. Google 到底做了什么 <a class="header-anchor" href="#_2-google-到底做了什么" aria-label="Permalink to &quot;2. Google 到底做了什么&quot;">​</a></h2><p>Google DeepMind 为 Gemini API 构建了一个轻量 developer skill，核心内容并不复杂，只有四类：</p><ol><li><strong>Gemini API 的高层能力说明</strong></li><li><strong>当前 models 和各语言 SDK 列表</strong></li><li><strong>基础示例代码</strong></li><li><strong>文档入口点，作为 source of truth</strong></li></ol><p>这套设计非常克制。它没有试图把全部文档塞进 prompt，而是提供：</p><ul><li>最小必要 guidance</li><li>最新正确入口</li><li>明确鼓励 agent 去文档源头取新信息</li></ul><p>也就是说，它不是“替代文档”，而是“把 agent 送上正确入口”。</p><p>这个判断很重要，因为很多知识注入方案最后都会犯两个错：</p><ul><li>要么塞太多，导致 context 污染</li><li>要么塞太少，只是口号级提醒</li></ul><p>Google 这套 skill 比较像一份面向 agent 的 SDK 使用导览卡。</p><hr><h2 id="_3-真正震撼的是-baseline-而不是加-skill-后的高分" tabindex="-1">3. 真正震撼的是 baseline，而不是加 skill 后的高分 <a class="header-anchor" href="#_3-真正震撼的是-baseline-而不是加-skill-后的高分" aria-label="Permalink to &quot;3. 真正震撼的是 baseline，而不是加 skill 后的高分&quot;">​</a></h2><h3 id="_3-1-eval-设置很简单-但抓得很准" tabindex="-1">3.1 eval 设置很简单，但抓得很准 <a class="header-anchor" href="#_3-1-eval-设置很简单-但抓得很准" aria-label="Permalink to &quot;3.1 eval 设置很简单，但抓得很准&quot;">​</a></h3><p>他们做了一个包含 <strong>117 个 prompts</strong> 的 evaluation harness，任务覆盖：</p><ul><li>agentic coding</li><li>chatbot 构建</li><li>document processing</li><li>streaming content</li><li>多种 Gemini SDK 特性使用</li></ul><p>测试分两种模式：</p><ul><li><strong>vanilla</strong>：直接提示模型</li><li><strong>with skill</strong>：给模型 Gemini CLI 类似的 system instruction，再提供 <code>activate_skill</code> 和 <code>fetch_url</code> 两个工具</li></ul><p>判错标准也很实用：<strong>只要用了旧 SDK，就算失败。</strong></p><p>这个标准非常工程化。因为在真实开发里，旧 SDK 代码即使能跑，也意味着：</p><ul><li>维护债务</li><li>文档对不上</li><li>示例不兼容</li><li>后续升级更难</li></ul><h3 id="_3-2-最值得记住的数字" tabindex="-1">3.2 最值得记住的数字 <a class="header-anchor" href="#_3-2-最值得记住的数字" aria-label="Permalink to &quot;3.2 最值得记住的数字&quot;">​</a></h3><p>文章里最有冲击力的一组数字是：</p><table tabindex="0"><thead><tr><th>模型</th><th>无 skill</th><th>有 skill</th><th>观察</th></tr></thead><tbody><tr><td>Gemini 3.0 Pro</td><td>6.8%</td><td>约 96%+</td><td>极低 baseline，被 skill 大幅拉升</td></tr><tr><td>Gemini 3.0 Flash</td><td>6.8%</td><td>约 96%+</td><td>同上</td></tr><tr><td>Gemini 3.1 Pro</td><td>28%</td><td>约 96.6%</td><td>最新模型也仍然高度依赖知识注入</td></tr><tr><td>Gemini 2.5 系列</td><td>有提升</td><td>明显低于 3.x</td><td>reasoning ceiling 明显存在</td></tr></tbody></table><p>这组数据的重点不是“skill 好棒”。</p><p>重点其实是：<strong>vanilla baseline 低得惊人。</strong></p><p>一个最新模型，如果不知道当前 SDK 应该怎么用，那在工程任务里就几乎不可用。</p><hr><h2 id="_4-技术上到底说明了什么" tabindex="-1">4. 技术上到底说明了什么 <a class="header-anchor" href="#_4-技术上到底说明了什么" aria-label="Permalink to &quot;4. 技术上到底说明了什么&quot;">​</a></h2><h3 id="_4-1-skill-确实有效-但它吃模型推理能力" tabindex="-1">4.1 skill 确实有效，但它吃模型推理能力 <a class="header-anchor" href="#_4-1-skill-确实有效-但它吃模型推理能力" aria-label="Permalink to &quot;4.1 skill 确实有效，但它吃模型推理能力&quot;">​</a></h3><p>Google 明确说，2.5 系列也能从 skill 获益，但提升远不如 3 系列。这其实说明一件事：</p><blockquote><p>skill 不是魔法，它只是把正确知识放到模型面前。模型有没有能力正确吸收、组合、执行，仍然取决于推理能力本身。</p></blockquote><p>所以更准确地说，不是“skill 提高能力”，而是：</p><ul><li>skill 补齐知识缺口</li><li>reasoning 决定知识能被转化为多少有效行动</li></ul><p>这对所有 agent 系统都成立。</p><p>如果底模推理不够，skill 最后可能只变成：</p><ul><li>会背一点新的 API 名字</li><li>但不会在复杂任务里稳定使用</li></ul><h3 id="_4-2-最低分项是-sdk-usage-反而说明评测抓住了真实痛点" tabindex="-1">4.2 最低分项是 SDK Usage，反而说明评测抓住了真实痛点 <a class="header-anchor" href="#_4-2-最低分项是-sdk-usage-反而说明评测抓住了真实痛点" aria-label="Permalink to &quot;4.2 最低分项是 SDK Usage，反而说明评测抓住了真实痛点&quot;">​</a></h3><p>文中提到表现最差的类别是 SDK Usage，pass rate 也还有 95%。失败样本里有一些 prompt 明确要求 Gemini 2.0 模型等旧路径。</p><p>这个细节很重要。因为它说明这套评测并不是在考“会不会抄文档”，而是在考：</p><ul><li>模型能不能在模糊、带噪、甚至带旧习惯的请求里</li><li>仍然回到当前正确接口</li></ul><p>这和真实开发环境非常接近。</p><p>用户不会总给你一份规范、干净、版本对齐的需求。很多时候需求本身就混着旧概念和新概念。</p><hr><h2 id="_5-真正更重要的-是-google-承认了它的局限" tabindex="-1">5. 真正更重要的，是 Google 承认了它的局限 <a class="header-anchor" href="#_5-真正更重要的-是-google-承认了它的局限" aria-label="Permalink to &quot;5. 真正更重要的，是 Google 承认了它的局限&quot;">​</a></h2><p>这篇最成熟的地方，不是秀结果，而是他们很直接地写出了两个问题。</p><h3 id="_5-1-agents-md-可能比-skill-更有效" tabindex="-1">5.1 AGENTS.md 可能比 skill 更有效 <a class="header-anchor" href="#_5-1-agents-md-可能比-skill-更有效" aria-label="Permalink to &quot;5.1 AGENTS.md 可能比 skill 更有效&quot;">​</a></h3><p>文章明确提到，他们知道 Vercel 的结论：<strong>direct instruction through AGENTS.md can be more effective than using skills</strong>。</p><p>这句话的分量很大。</p><p>因为它其实在承认：</p><ul><li>skill 不是唯一的 live knowledge 注入形式</li><li>甚至不一定是最有效的一种</li><li>项目级、默认被读取、与任务现场强绑定的 instruction surface，往往更强</li></ul><p>为什么 AGENTS.md 往往更强？大概有几个原因：</p><ol><li><p><strong>离任务现场更近</strong></p><ul><li>它就在 repo/workspace 里</li><li>agent 更容易默认读到</li></ul></li><li><p><strong>不依赖额外激活</strong></p><ul><li>skill 往往要通过特定工具或系统提示触发</li><li>AGENTS.md 更像天然环境的一部分</li></ul></li><li><p><strong>更适合项目定制</strong></p><ul><li>skill 偏通用</li><li>AGENTS.md 可以写具体 repo 的约束、偏好、版本和操作边界</li></ul></li><li><p><strong>上下文优先级可能更高</strong></p><ul><li>系统已经学会关注当前工作目录里的说明文件</li><li>比外加 skill 更稳定</li></ul></li></ol><h3 id="_5-2-skill-更新机制现在很差-这不是小问题" tabindex="-1">5.2 skill 更新机制现在很差，这不是小问题 <a class="header-anchor" href="#_5-2-skill-更新机制现在很差-这不是小问题" aria-label="Permalink to &quot;5.2 skill 更新机制现在很差，这不是小问题&quot;">​</a></h3><p>Google 另一句很关键的话是：</p><blockquote><p>there isn&#39;t a great skill update story, other than requiring users to update manually</p></blockquote><p>这几乎直接点中了 skill 体系的命门。</p><p>如果 skill 更新依赖手动，那么就会出现：</p><ul><li>用户工作区里残留旧 skill</li><li>agent 持续读取过时 guidance</li><li>看似有知识补充，实际上是错误补充</li><li>错误 guidance 的伤害，可能比没有 guidance 更大</li></ul><p>这不是一个可以靠“维护勤快一点”解决的小问题，而是分发机制问题。</p><p>一旦 knowledge artifact 会过期，它就必须考虑：</p><ul><li>版本标记</li><li>更新提醒</li><li>源头校验</li><li>失效策略</li><li>workspace 中旧副本的清理</li></ul><p>不然系统最终会陷入一种很糟糕的状态：</p><blockquote><p>用户以为 agent 有最新知识，实际上 agent 正在被旧知识稳定误导。</p></blockquote><hr><h2 id="_6-wlb-视角-这篇真正透露了什么平台判断" tabindex="-1">6. WLB 视角，这篇真正透露了什么平台判断 <a class="header-anchor" href="#_6-wlb-视角-这篇真正透露了什么平台判断" aria-label="Permalink to &quot;6. WLB 视角，这篇真正透露了什么平台判断&quot;">​</a></h2><h3 id="_6-1-训练不是知识交付的终点" tabindex="-1">6.1 训练不是知识交付的终点 <a class="header-anchor" href="#_6-1-训练不是知识交付的终点" aria-label="Permalink to &quot;6.1 训练不是知识交付的终点&quot;">​</a></h3><p>过去很多模型公司默认的叙事是：</p><ul><li>模型训练得更好</li><li>知识自然更全</li><li>下游使用问题会被大模型吞掉</li></ul><p>但这篇文章的存在本身就在反驳这种叙事。</p><p>对于工程世界来说：</p><ul><li>SDK 在变</li><li>docs 在变</li><li>推荐路径在变</li><li>best practice 在变</li></ul><p>所以知识交付不能只靠 pretraining。训练完成之后，还必须有一套<strong>持续把当前现实注入推理现场</strong>的机制。</p><h3 id="_6-2-知识注入面-本身会成为新的平台层" tabindex="-1">6.2 “知识注入面”本身会成为新的平台层 <a class="header-anchor" href="#_6-2-知识注入面-本身会成为新的平台层" aria-label="Permalink to &quot;6.2 “知识注入面”本身会成为新的平台层&quot;">​</a></h3><p>从 AGENTS.md、skills、MCP 到 fetch_url/doc tools，大家其实都在争夺同一件事：</p><ul><li>谁来作为最新知识的入口</li><li>谁来定义知识被怎样组织给 agent</li><li>谁来决定 source of truth 与 workspace 之间的关系</li></ul><p>这意味着之后 agent 平台的竞争，不只在模型本身，也在：</p><ul><li>instruction surface 设计</li><li>live knowledge transport</li><li>artifact update story</li><li>repo-local context 与 remote source 的组合方式</li></ul><h3 id="_6-3-轻量方案的优势-和轻量方案的脆弱性-是同一枚硬币两面" tabindex="-1">6.3 轻量方案的优势，和轻量方案的脆弱性，是同一枚硬币两面 <a class="header-anchor" href="#_6-3-轻量方案的优势-和轻量方案的脆弱性-是同一枚硬币两面" aria-label="Permalink to &quot;6.3 轻量方案的优势，和轻量方案的脆弱性，是同一枚硬币两面&quot;">​</a></h3><p>skill 的优点很明显：</p><ul><li>轻</li><li>快</li><li>易安装</li><li>不需要部署新服务</li></ul><p>但它的脆弱性也正来自轻：</p><ul><li>生命周期弱</li><li>版本控制弱</li><li>自动更新弱</li><li>失效管理弱</li></ul><p>如果系统不把这些补齐，轻量最终会变成脆弱。</p><hr><h2 id="_7-gsd-视角-对我们做-agent-系统最实用的启发" tabindex="-1">7. GSD 视角，对我们做 agent 系统最实用的启发 <a class="header-anchor" href="#_7-gsd-视角-对我们做-agent-系统最实用的启发" aria-label="Permalink to &quot;7. GSD 视角，对我们做 agent 系统最实用的启发&quot;">​</a></h2><h3 id="_7-1-先测-vanilla-baseline-别上来就吹增强方案" tabindex="-1">7.1 先测 vanilla baseline，别上来就吹增强方案 <a class="header-anchor" href="#_7-1-先测-vanilla-baseline-别上来就吹增强方案" aria-label="Permalink to &quot;7.1 先测 vanilla baseline，别上来就吹增强方案&quot;">​</a></h3><p>Google 这篇最专业的地方之一，是他们先把 vanilla baseline 测出来了，而且结果不太好看。</p><p>这很重要，因为很多系统优化都会犯一个毛病：</p><ul><li>加了 skill</li><li>加了 memory</li><li>加了 tool</li><li>分数上去了</li><li>但没人知道原始 baseline 到底烂在哪</li></ul><p>没有 baseline，你就分不清：</p><ul><li>是增强方案真有用</li><li>还是测试集本来就容易</li><li>或者只是碰巧吃到了某个 prompt 分布</li></ul><h3 id="_7-2-评价标准要贴生产-而不是贴-demo" tabindex="-1">7.2 评价标准要贴生产，而不是贴 demo <a class="header-anchor" href="#_7-2-评价标准要贴生产-而不是贴-demo" aria-label="Permalink to &quot;7.2 评价标准要贴生产，而不是贴 demo&quot;">​</a></h3><p>“用了旧 SDK 就算失败”这个规则特别对味。</p><p>因为生产里最烦的不是答非所问，而是<strong>看起来差不多，但方向已经过时</strong>。</p><p>我们做自己的工具和技能体系时，判错标准也应该更像这样：</p><ul><li>用了 deprecated path 算失败</li><li>违反当前推荐实践算失败</li><li>引用了错误 source of truth 算失败</li><li>只要会把后续维护成本拉高，也该算失败</li></ul><h3 id="_7-3-把知识入口放在默认会被读到的位置" tabindex="-1">7.3 把知识入口放在默认会被读到的位置 <a class="header-anchor" href="#_7-3-把知识入口放在默认会被读到的位置" aria-label="Permalink to &quot;7.3 把知识入口放在默认会被读到的位置&quot;">​</a></h3><p>如果一个知识机制需要：</p><ul><li>额外安装</li><li>手动激活</li><li>特定 system prompt 才能触发</li></ul><p>那它在真实使用里就一定会掉链子。</p><p>所以对我们来说，优先级大概应该是：</p><ol><li><strong>AGENTS.md / repo-local instructions</strong></li><li><strong>稳定默认可见的工具说明或 TOOLS.md</strong></li><li><strong>需要显式激活的 skill / plugin</strong></li><li><strong>最后才是临时查文档</strong></li></ol><p>因为离工作现场越近、默认可见度越高的知识入口，执行成功率越高。</p><h3 id="_7-4-任何会过期的知识工件-都必须设计更新故事" tabindex="-1">7.4 任何会过期的知识工件，都必须设计更新故事 <a class="header-anchor" href="#_7-4-任何会过期的知识工件-都必须设计更新故事" aria-label="Permalink to &quot;7.4 任何会过期的知识工件，都必须设计更新故事&quot;">​</a></h3><p>这是我觉得最该抄的一点。</p><p>很多团队喜欢做：</p><ul><li>规范片段</li><li>skill 包</li><li>prompt 模板</li><li>内部最佳实践卡片</li></ul><p>但做好第一版之后，就默认它永远有用。实际上不是。</p><p>这类工件只要涉及：</p><ul><li>SDK</li><li>API</li><li>产品版本</li><li>推荐工作流</li></ul><p>就一定会过期。</p><p>那你就得从第一天开始问：</p><ul><li>它怎么标版本？</li><li>谁负责更新？</li><li>旧副本怎么处理？</li><li>agent 怎么知道它可能过期？</li><li>有没有办法优先回源？</li></ul><hr><h2 id="_8-对-openclaw-我们自己的直接借鉴" tabindex="-1">8. 对 OpenClaw / 我们自己的直接借鉴 <a class="header-anchor" href="#_8-对-openclaw-我们自己的直接借鉴" aria-label="Permalink to &quot;8. 对 OpenClaw / 我们自己的直接借鉴&quot;">​</a></h2><h3 id="_8-1-agents-md-继续做主知识面-skill-做补充-不要反过来" tabindex="-1">8.1 AGENTS.md 继续做主知识面，skill 做补充，不要反过来 <a class="header-anchor" href="#_8-1-agents-md-继续做主知识面-skill-做补充-不要反过来" aria-label="Permalink to &quot;8.1 AGENTS.md 继续做主知识面，skill 做补充，不要反过来&quot;">​</a></h3><p>这篇和我们自己的使用经验基本一致：</p><ul><li><strong>AGENTS.md 适合承载主约束</strong></li><li>skill 更适合承载某类专业任务的执行手册</li></ul><p>如果把核心行为约束都塞进 skill，而 skill 又不是默认必读，那最后一定会出现行为漂移。</p><h3 id="_8-2-所有-skill-都应该显式标-最后验证时间-和-源头链接" tabindex="-1">8.2 所有 skill 都应该显式标“最后验证时间”和“源头链接” <a class="header-anchor" href="#_8-2-所有-skill-都应该显式标-最后验证时间-和-源头链接" aria-label="Permalink to &quot;8.2 所有 skill 都应该显式标“最后验证时间”和“源头链接”&quot;">​</a></h3><p>如果一个 skill 里包含：</p><ul><li>CLI 用法</li><li>API 路径</li><li>平台行为</li></ul><p>那至少应该带上：</p><ul><li>最后验证日期</li><li>验证环境</li><li>官方 source of truth 链接</li><li>可能失效的部分</li></ul><p>这样即使内容老化，agent 和人也更容易识别风险。</p><h3 id="_8-3-对会变化快的知识-优先给入口-不要给伪完整摘要" tabindex="-1">8.3 对会变化快的知识，优先给入口，不要给伪完整摘要 <a class="header-anchor" href="#_8-3-对会变化快的知识-优先给入口-不要给伪完整摘要" aria-label="Permalink to &quot;8.3 对会变化快的知识，优先给入口，不要给伪完整摘要&quot;">​</a></h3><p>Google 这个 skill 的设计很聪明的地方，是它并没有试图摘要一切。</p><p>对变化快的东西，更好的写法通常是：</p><ul><li>先给判断框架</li><li>再给最新入口</li><li>再告诉 agent 去哪里取真值</li></ul><p>而不是塞一大段“截至某月某日看起来完整”的知识。</p><h3 id="_8-4-可以考虑给-skill-doc-工件增加-过期提醒-机制" tabindex="-1">8.4 可以考虑给 skill / doc 工件增加“过期提醒”机制 <a class="header-anchor" href="#_8-4-可以考虑给-skill-doc-工件增加-过期提醒-机制" aria-label="Permalink to &quot;8.4 可以考虑给 skill / doc 工件增加“过期提醒”机制&quot;">​</a></h3><p>比如：</p><ul><li>超过 N 天未验证就提示谨慎使用</li><li>引用 source of truth 前先 fetch 一次最新页面</li><li>对高变化主题优先提示“以官方文档为准”</li></ul><p>这不一定优雅，但比静悄悄过期强得多。</p><hr><h2 id="_9-一个更冷的判断-这篇其实在说-agent-需要-知识运维" tabindex="-1">9. 一个更冷的判断：这篇其实在说 agent 需要“知识运维” <a class="header-anchor" href="#_9-一个更冷的判断-这篇其实在说-agent-需要-知识运维" aria-label="Permalink to &quot;9. 一个更冷的判断：这篇其实在说 agent 需要“知识运维”&quot;">​</a></h2><p>很多人理解 agent infra，脑子里先出现的是：</p><ul><li>model routing</li><li>memory</li><li>tools</li><li>planning</li><li>eval</li></ul><p>但这篇提醒我们，还有一层经常被低估的基础设施：</p><p><strong>knowledge ops。</strong></p><p>也就是：</p><ul><li>最新知识从哪里来</li><li>以什么形式进入 agent</li><li>如何判断已过期</li><li>如何让错误知识退出系统</li><li>如何在 repo-local knowledge 和 remote truth 之间取得平衡</li></ul><p>这层如果不补起来，模型越会执行，反而越可能高效率地执行错误知识。</p><hr><h2 id="联合结论" tabindex="-1">联合结论 <a class="header-anchor" href="#联合结论" aria-label="Permalink to &quot;联合结论&quot;">​</a></h2><p>Google DeepMind 这篇关于 agent skills 的文章，表面上是在展示一个 Gemini API developer skill 的效果，实质上是在把一个更底层的现实挑明：<strong>工程世界的知识是流动的，而模型知识天然会冻结。</strong></p><p>它给出的核心工程判断有六个：</p><ol><li><strong>训练后知识缺口是 coding agent 的一等问题，不是边角料问题。</strong></li><li><strong>轻量 knowledge injection 确实有效，能把 SDK 使用正确率从极低 baseline 拉到高可用区间。</strong></li><li><strong>skill 的上限仍然受模型 reasoning 能力约束。</strong></li><li><strong>AGENTS.md 这类 repo-local、默认可见的 instruction surface，往往比 skill 更稳定有效。</strong></li><li><strong>任何会过期的知识工件，如果没有更新机制，迟早会从资产变成负债。</strong></li><li><strong>Agent 平台未来不只需要 tool infra，还需要 knowledge infra。</strong></li></ol><hr><p><em>上一篇：<a href="/LIP/bestpractice/google-litert-on-device-ai.html">/bestpractice/google-litert-on-device-ai</a></em></p>',163)])])}const c=i(o,[["render",r]]);export{u as __pageData,c as default};
